SELECT error_fingerprint AS errorFingerprint, COUNT(id) AS id FROM observability_events
WHERE event_type = 'error' AND error_fingerprint IS NOT NULL
GROUP BY error_fingerprint ORDER BY id DESC LIMIT #{limit}

SELECT error_fingerprint AS errorFingerprint, COUNT(id) AS id FROM observability_events
WHERE event_type = 'error' AND error_fingerprint IS NOT NULL
AND created_at >= #{startDate} AND created_at <= #{endDate}
GROUP BY error_fingerprint ORDER BY id DESC LIMIT #{limit}

